              }
              return prev + points;
            });
            showFeedback(icon.x, icon.y, true, points, icon.name);
            playSound('correct');
            createExplosion(icon.x + 25, icon.y + 25, '#4CAF50');
          } else {
            setScore((prev) => prev - 5);
            showFeedback(icon.x, icon.y, false, -5, icon.name);
            playSound('incorrect');
          }

          icons.splice(iconIndex, 1);
          return false;
        }
        return true;
      });
    });

    if (iconsRef.current.length === 0 && timeLeft > 0) {
      playSound('levelup');
      setCurrentInstructionIndex((prev) => {
        const newIndex = (prev + 1) % instructions.length;

        // If we've gone through all instructions, generate new ones
        if (newIndex === 0) {
