      return () => clearInterval(timer);
    } else if (timeLeft === 0 && !gameOverHandled) {
      handleGameOver();
    }
  }, [timeLeft, gameOver, gameOverHandled, gameState.isPlaying]);

  // Handle game over
  const handleGameOver = () => {
